package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.StringReader;
import java.lang.reflect.Method;
import java.lang.reflect.Type;

class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void fromJson_withValidJsonReaderAndType_returnsObject() throws IOException {
    String json = "\"test\"";
    JsonReader jsonReader = new JsonReader(new StringReader(json));
    Type type = String.class;

    String result = gson.fromJson(jsonReader, type);

    assertEquals("test", result);
  }

  @Test
  void fromJson_withNullJsonReader_throwsNullPointerException() {
    Type type = String.class;
    assertThrows(NullPointerException.class, () -> gson.fromJson((JsonReader) null, type));
  }

  @Test
  void fromJson_withMalformedJson_throwsJsonSyntaxException() {
    String malformedJson = "{ unquoted_key: \"value\" }";
    JsonReader jsonReader = new JsonReader(new StringReader(malformedJson));
    Type type = Object.class;

    assertThrows(JsonSyntaxException.class, () -> gson.fromJson(jsonReader, type));
  }

  @Test
  void fromJson_withJsonIOException_throwsJsonIOException() throws IOException {
    JsonReader jsonReader = mock(JsonReader.class);
    Type type = Object.class;
    doThrow(new IOException("io error")).when(jsonReader).peek();

    assertThrows(JsonIOException.class, () -> gson.fromJson(jsonReader, type));
  }

  @Test
  void fromJson_invokesPrivateFromJsonWithTypeToken() throws Throwable {
    String json = "\"reflectionTest\"";
    JsonReader jsonReader = new JsonReader(new StringReader(json));
    Type type = String.class;

    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonReader.class, TypeToken.class);
    fromJsonMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    String result = (String) fromJsonMethod.invoke(gson, jsonReader, TypeToken.get(type));

    assertEquals("reflectionTest", result);
  }
}
